let array = [];
array.push(1);
console.log(array); // Expected output: [1]

let array = [1, 2, 3];
let firstElement = array[0];
console.log(firstElement); // Expected output: 1

let array = [1, 2, 3];
let length = array.length;
console.log(length); // Expected output: 3

let array = [1, 2, 3];
array[0] = 4;
console.log(array); // Expected output: [4, 2, 3]

let array = [1, 2, 3];
array.shift();
console.log(array); // Expected output: [2, 3]

let array1 = [1, 2, 3];
let array2 = [4, 5, 6];
let combinedArray = array1.concat(array2);
console.log(combinedArray); // Expected output: [1, 2, 3, 4, 5, 6]

let array = [1, 2, 3];
array.reverse();
console.log(array); // Expected output: [3, 2, 1]

let array = [3, 1, 2];
array.sort(function(a, b) { return a - b; });
console.log(array); // Expected output: [1, 2, 3]

let array = [1, 2, 3];
let length = array.length;
console.log(length); // Expected output: 3

let array = ["Apple", "Banana", "Cherry"];
let fruit = array[1];
console.log(fruit); // Expected output: "Banana"

let array = ["Apple", "Banana"];
array.push("Cherry");
console.log(array); // Expected output: ["Apple", "Banana", "Cherry"]

let array = ["Apple", "Cherry"];
array.splice(1, 0, "Banana");
console.log(array); // Expected output: ["Apple", "Banana", "Cherry"]

let array = ["Apple", "Banana", "Cherry"];
let index = array.indexOf("Banana");
if (index > -1) { array.splice(index, 1); }
console.log(array); // Expected output: ["Apple", "Cherry"]

let array = ["Apple", "Banana", "Cherry"];
let length = array.length;
console.log(length); // Expected output: 3

let array = ["Banana", "Apple", "Cherry"];
array.sort();
console.log(array); // Expected output: ["Apple", "Banana", "Cherry"]

let array = ["Apple", "Banana", "Cherry"];
array.reverse();
console.log(array); // Expected output: ["Cherry", "Banana", "Apple"]

let array = ["Apple", "Banana", "Cherry"];
let index = array.indexOf("Banana");
if (index !== -1) {
  array.splice(index, 1);
}
console.log(array); // Expected output: ["Apple", "Cherry"]

let array = ["Apple", "Banana", "Cherry"];
let str = array.join(', ');
console.log(str); // Expected output: "Apple, Banana, Cherry"

let array = ["Apple", "Banana", "Cherry"];
let lastElement = array.pop();
array.unshift(lastElement);
console.log(array); // Expected output: ["Cherry", "Apple", "Banana"]
